#include<bits/stdc++.h>
using namespace std;
bool f(string x,string y){
	for(int i=0;i<x.size();i++){
		if(!(x[i]==y[i]||x[i]=='?'||y[i]=='?'))return false;
	}return true;
}
int main(void){ 
	string a,b,c;
	cin>>a>>b;
	for(int i=0;i<=a.size();i++){
		c="";
		for(int j=i;j<i+b.size();j++){
			c+=a[j];
		}
		if(f(c,b))cout<<i+1<<' '<<i+b.size()<<"\n";
	}
    return false;
}
